import React from 'react';
import Tab from 'react-bootstrap/Tab';
import Tabs from 'react-bootstrap/Tabs';

function CustomTab({ tabs }) {
    return (
      <Tabs defaultActiveKey="section-0" id="custom-tab">
        {tabs.map((tab, index) => (
          <Tab eventKey={tab.eventKey} title={tab.title} key={index} disabled={tab.disabled}>
            <CustomSection>{tab.content}</CustomSection>
          </Tab>
        ))}
      </Tabs>
    );
  }
  
  export default CustomTab;
